function deepClone(obj) {
  if (obj === null || typeof obj !== 'object') {
    return obj;
  }

  if (Array.isArray(obj)) {
    let cloneArr = [];
    for (let i = 0; i < obj.length; i++) {
      cloneArr[i] = deepClone(obj[i]);
    }
    return cloneArr;
  } else {
    let cloneObj = {};
    for (let key in obj) {
      cloneObj[key] = deepClone(obj[key]);
    }
    return cloneObj;
  }
}

